namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed initial fake data
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the app!"),
            CreateNotification("Your profile was updated."),
            CreateNotification("New feature: dark mode is available."),
        });
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            var newer = _notifications
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally; in a real app this would come from a database or message bus.
    /// </summary>
    public void SimulateIncoming()
    {
        lock (_lock)
        {
            if (Random.Shared.Next(0, 3) == 0) // ~33% chance each poll
            {
                var messages = new[]
                {
                    "Someone liked your post.",
                    "You have a new follower.",
                    "Your build succeeded.",
                    "Deployment to production completed.",
                    "Scheduled maintenance tonight at 10 PM.",
                    "Your subscription renews tomorrow.",
                };
                var msg = messages[Random.Shared.Next(messages.Length)];
                _notifications.Add(CreateNotification(msg));
            }
        }
    }

    private Notification CreateNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

