@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? notifications { get; set; }

    private int lastSeenId;
    private CancellationTokenSource? cts;

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we don't re-fetch data that was persisted from prerender
        notifications ??= await NotificationSvc.GetNotificationsAsync();
        lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is NOT called during prerender,
        // so the polling loop only starts once the page is truly interactive.
        if (firstRender)
        {
            cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

                // Simulate new notifications appearing on the server side
                NotificationSvc.SimulateIncoming();

                var newer = await NotificationSvc.GetNotificationsSinceAsync(lastSeenId);
                if (newer.Count > 0)
                {
                    notifications = newer.Concat(notifications!).ToList();
                    lastSeenId = notifications.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }
    }
}

